      throw error;
    }
    syncBranch = buildResultsSyncBranchName(targetBranch);
    await assertValidResultsBranchName(repoDir, syncBranch);
    await runGit(['push', '--porcelain', remote, `${sourceCommit}:refs/heads/${syncBranch}`], {
      cwd: repoDir,
    });
